class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j < s.length(); j++) {
                if (s[i] == target[0] && s[j] == target[1]) {
                    count++;
                    break;
                }
            }
        }
        return count;
    }
};
```

